DROP TABLE IF EXISTS player_performance;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE player_performance (
  perf_id int NOT NULL AUTO_INCREMENT,
  match_id int DEFAULT NULL,
  player_id int DEFAULT NULL,
  goals int DEFAULT '0',
  yellow_cards int DEFAULT '0',
  red_cards int DEFAULT '0',
  is_starter tinyint(1) DEFAULT '1',
  mins_played int DEFAULT '0',
  PRIMARY KEY (perf_id),
  KEY match_id (match_id),
  KEY player_id (player_id),
  CONSTRAINT player_performance_ibfk_1 FOREIGN KEY (match_id) REFERENCES matches (match_id),
  CONSTRAINT player_performance_ibfk_2 FOREIGN KEY (player_id) REFERENCES players (player_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
